library(sf)
library(dplyr)
library(plotly)
library(leaflet)

gpkg_path &lt;- "../data/river-water-quality/river-water-quality-nitrogen-trends-1991-2020.gpkg"

layers &lt;- st_layers(gpkg_path)
rwq &lt;- st_read(gpkg_path, layer = layers$name[1], quiet = TRUE)
rwq_tbl &lt;- st_drop_geometry(rwq)

pick_col &lt;- function(df, candidates) {
  hits &lt;- intersect(candidates, names(df))
  if (length(hits) == 0) NA_character_ else hits[1]
}

parameter_col &lt;- pick_col(
  rwq_tbl,
  c("parameter", "Parameter", "indicator", "Indicator", "np_id_name", "np_id", "attribute")
)
period_col &lt;- pick_col(
  rwq_tbl,
  c("period", "Period", "trend_period", "window", "time_window", "assessment_period")
)
trend_col &lt;- pick_col(
  rwq_tbl,
  c("trend", "Trend", "trend_direction", "direction", "Direction", "classification", "trend_class")
)

if (!is.na(trend_col) && !is.na(period_col)) {
  trend_profile &lt;- rwq_tbl |&gt;
    mutate(
      trend_band = as.character(.data[[trend_col]]),
      period_band = as.character(.data[[period_col]])
    ) |&gt;
    filter(!is.na(trend_band), !is.na(period_band), trend_band != "", period_band != "") |&gt;
    count(period_band, trend_band, name = "records")

  plot_ly(
    trend_profile,
    x = ~period_band,
    y = ~records,
    color = ~trend_band,
    type = "bar"
  ) |&gt;
    layout(
      barmode = "stack",
      xaxis = list(title = "Assessment period"),
      yaxis = list(title = "Number of site records"),
      legend = list(title = list(text = "Trend direction"))
    )
} else if (!is.na(trend_col)) {
  trend_profile &lt;- rwq_tbl |&gt;
    mutate(trend_band = as.character(.data[[trend_col]])) |&gt;
    filter(!is.na(trend_band), trend_band != "") |&gt;
    count(trend_band, name = "records")

  plot_ly(
    trend_profile,
    x = ~reorder(trend_band, records),
    y = ~records,
    type = "bar",
    marker = list(color = "#2b7a78")
  ) |&gt;
    layout(
      xaxis = list(title = "Trend direction"),
      yaxis = list(title = "Number of site records"),
      margin = list(b = 120)
    )
} else {
  fallback_col &lt;- ifelse(is.na(parameter_col), names(rwq_tbl)[1], parameter_col)

  coverage_profile &lt;- rwq_tbl |&gt;
    mutate(group_name = as.character(.data[[fallback_col]])) |&gt;
    filter(!is.na(group_name), group_name != "") |&gt;
    count(group_name, sort = TRUE, name = "records") |&gt;
    slice_head(n = 12)

  plot_ly(
    coverage_profile,
    x = ~reorder(group_name, records),
    y = ~records,
    type = "bar",
    marker = list(color = "#2b7a78")
  ) |&gt;
    layout(
      xaxis = list(title = "Indicator field"),
      yaxis = list(title = "Number of records"),
      margin = list(b = 160)
    )
}








