rwq_map &lt;- rwq


# convert dataframe to sf object: coerce coords to numeric and remove invalid rows
rwq_map$long_num &lt;- as.numeric(rwq_map$long)
rwq_map$lat_num &lt;- as.numeric(rwq_map$lat)
# drop rows with NA coords (including non-numeric coercion results)
rwq_map &lt;- rwq_map[!is.na(rwq_map$long_num) & !is.na(rwq_map$lat_num), ]
rwq_map &lt;- st_as_sf(rwq_map, coords = c("long_num", "lat_num"), crs = 4326, remove = TRUE)


if (nrow(rwq_map) &gt; 0) {
  rwq_map &lt;- suppressWarnings(st_transform(rwq_map, 4326))
}

rwq_map_tbl &lt;- st_drop_geometry(rwq_map)

site_col &lt;- pick_col(rwq_map_tbl, c("site_name", "site", "s_id", "site_id", "location", "name"))
parameter_col &lt;- pick_col(rwq_map_tbl, c("parameter", "Parameter", "indicator", "np_id_name", "np_id"))
period_col &lt;- pick_col(rwq_map_tbl, c("period", "Period", "trend_period", "window", "assessment_period"))
trend_col &lt;- pick_col(rwq_map_tbl, c("trend", "Trend", "trend_direction", "direction", "classification", "trend_class"))
value_col &lt;- pick_col(rwq_map_tbl, c("median", "result", "Result", "value", "Value", "slope", "Sen_slope", "sen_slope"))

popup_fields &lt;- unique(na.omit(c(site_col, parameter_col, period_col, trend_col, value_col)))

if (length(popup_fields) == 0) {
  popup_text &lt;- rep("River monitoring site", nrow(rwq_map_tbl))
} else {
  popup_text &lt;- apply(
    rwq_map_tbl[, popup_fields, drop = FALSE],
    1,
    function(x) {
      vals &lt;- ifelse(is.na(x) | x == "", "NA", as.character(x))
      paste0(names(x), ": ", vals, collapse = "&lt;br&gt;")
    }
  )
}

